CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
CREATE TABLE IF NOT EXISTS tenants(id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), name TEXT NOT NULL, code TEXT UNIQUE NOT NULL, status TEXT DEFAULT 'active', logo_url TEXT, created_at TIMESTAMP DEFAULT now());
CREATE TABLE IF NOT EXISTS users(id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), tenant_id UUID REFERENCES tenants(id), name TEXT NOT NULL, email TEXT UNIQUE NOT NULL, password_hash TEXT NOT NULL, role TEXT NOT NULL, department TEXT, status TEXT DEFAULT 'active', created_at TIMESTAMP DEFAULT now());
CREATE TABLE IF NOT EXISTS subscription_plans(id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), name TEXT UNIQUE NOT NULL, price NUMERIC DEFAULT 0, user_limit INT DEFAULT 5, task_limit INT DEFAULT 1000, features TEXT, created_at TIMESTAMP DEFAULT now());
CREATE TABLE IF NOT EXISTS subscriptions(id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), tenant_id UUID REFERENCES tenants(id), plan_id UUID REFERENCES subscription_plans(id), start_date DATE DEFAULT CURRENT_DATE, end_date DATE, status TEXT DEFAULT 'active');
CREATE TABLE IF NOT EXISTS invoices(id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), tenant_id UUID REFERENCES tenants(id), invoice_no TEXT UNIQUE NOT NULL, amount NUMERIC NOT NULL, status TEXT DEFAULT 'unpaid', invoice_date DATE DEFAULT CURRENT_DATE, due_date DATE, notes TEXT);
CREATE TABLE IF NOT EXISTS tasks(id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), tenant_id UUID REFERENCES tenants(id), task_no TEXT UNIQUE NOT NULL, title TEXT NOT NULL, description TEXT, department TEXT, location TEXT, category TEXT, priority TEXT DEFAULT 'Medium', status TEXT DEFAULT 'Open', assigned_to UUID REFERENCES users(id), created_by UUID REFERENCES users(id), due_at TIMESTAMP, created_at TIMESTAMP DEFAULT now(), updated_at TIMESTAMP DEFAULT now());
CREATE TABLE IF NOT EXISTS complaints(id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), tenant_id UUID REFERENCES tenants(id), complaint_no TEXT UNIQUE NOT NULL, department TEXT, location TEXT, category TEXT, description TEXT, priority TEXT DEFAULT 'Medium', photo_path TEXT, audio_path TEXT, video_path TEXT, task_id UUID REFERENCES tasks(id), created_at TIMESTAMP DEFAULT now());
CREATE TABLE IF NOT EXISTS comments(id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), tenant_id UUID REFERENCES tenants(id), task_id UUID REFERENCES tasks(id) ON DELETE CASCADE, user_id UUID REFERENCES users(id), comment TEXT NOT NULL, created_at TIMESTAMP DEFAULT now());
CREATE TABLE IF NOT EXISTS attachments(id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), tenant_id UUID REFERENCES tenants(id), task_id UUID REFERENCES tasks(id) ON DELETE CASCADE, user_id UUID REFERENCES users(id), file_name TEXT, file_path TEXT, mime_type TEXT, size_bytes INT, created_at TIMESTAMP DEFAULT now());
CREATE TABLE IF NOT EXISTS notifications(id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), tenant_id UUID REFERENCES tenants(id), user_id UUID REFERENCES users(id), title TEXT, message TEXT, is_read BOOLEAN DEFAULT false, created_at TIMESTAMP DEFAULT now());
CREATE TABLE IF NOT EXISTS audit_logs(id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), tenant_id UUID REFERENCES tenants(id), user_id UUID REFERENCES users(id), action TEXT, entity_type TEXT, entity_id UUID, details TEXT, created_at TIMESTAMP DEFAULT now());
